final:
module rising_edge_detector(
    input                 clk,
    input                 rst,
    input                 signal_in,

    output reg            edge_detected
);

reg signal_out_q;

// Edge detector implementation
always @(posedge clk) begin
    if (rst) begin
        signal_out_q <= 1'b0;
        edge_detected <= 1'b0;
    end
    else begin
        signal_out_q <= signal_in;
        edge_detected <= signal_in & ~signal_out_q;
    end
end

endmodule
